module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);
    reg [3:0] cnt;
    reg [7:0] data;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'b0;
            data <= 8'b0;
            dout_parallel <= 8'b0;
            dout_valid <= 1'b0;
        end
        else begin
            if (din_valid) begin
                data <= {data[6:0], din_serial};
                cnt <= cnt + 4'b1;
                if (cnt == 4'b1111) begin
                    dout_parallel <= data;
                    dout_valid <= 1'b1;
                end
                else begin
                    dout_valid <= 1'b0;
                end
            end
            else begin
                dout_valid <= 1'b0;
            end
        end
    end
endmodule

module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

parameter IDLE = 3'b000;
parameter SUB = 3'b001;
parameter ADD = 3'b010;
parameter SHIFT = 3'b011;
parameter FINALIZE = 3'b100;

reg [2:0] state, next_state;
reg [15:0] neg_divisor;
reg [31:0] sr;
reg [15:0] sub_result;
reg [16:0] carry;
reg [4:0] cnt;
reg start_cnt;
reg result_sign;
reg [15:0] dividend_abs;
reg [15:0] divisor_abs;
reg done;

always @(*) begin
    case (state)
        IDLE: begin
            if (opn_valid && !res_valid) begin
                next_state = SUB;
            end else begin
                next_state = IDLE;
            end
        end
        SUB: begin
            if (cnt[4]) begin
                next_state = FINALIZE;
            end else begin
                next_state = SHIFT;
            end
        end
        SHIFT: begin
            next_state = SUB;
        end
        FINALIZE: begin
            next_state = IDLE;
        end
        default: next_state = IDLE;
    endcase
end

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        state <= IDLE;
        done <= 0;
        neg_divisor <= 0;
        sr <= 0;
        sub_result <= 0;
        carry <= 0;
        cnt <= 0;
        start_cnt <= 0;
        result_sign <= 0;
        dividend_abs <= 0;
        divisor_abs <= 0;
        res_valid <= 0;
        result <= 0;
    end else begin
        state <= next_state;
        case (next_state)
            IDLE: begin
                if (opn_valid && !res_valid) begin
                    done <= 0;
                    if (divisor[15] && sign) begin
                        divisor_abs <= (~divisor) + 1;
                    end else begin
                        divisor_abs <= divisor;
                    end
                    if (dividend[15] && sign) begin
                        dividend_abs <= (~dividend) + 1;
                    end else begin
                        dividend_abs <= dividend;
                    end
                    result_sign <= (divisor[15] ^ dividend[15]) && sign;
                    sr <= {16'b0, dividend_abs};
                    neg_divisor <= (~divisor_abs) + 1;
                    cnt <= 1;
                    start_cnt <= 1;
                end
            end
            SUB: begin
                if (cnt[4]) begin
                    done <= 1;
                    start_cnt <= 0;
                end
                sub_result <= sr[31:16] + neg_divisor;
                carry <= sub_result[15] ? 17'b0 : 17'b1;
            end
            SHIFT: begin
                if (cnt[4]) begin
                    done <= 1;
                    start_cnt <= 0;
                end
                sr <= {carry[15:0], sr[15:0]};
                cnt <= cnt + 1;
            end
            FINALIZE: begin
                if (done) begin
                    result <= result_sign ? ~(sr[15:0] - 1) : sr[15:0];
                    res_valid <= 1;
                end
            end
        endcase
    end
end
endmodule

module width_8to16
(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output reg valid_out,
    output reg [15:0] data_out
);
    reg [7:0] data_lock;
    reg flag;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            flag <= 1'b0;
        end
        else begin
            if (valid_in && !flag) begin
                data_lock <= data_in;
                flag <= 1'b1;
            end
            else if (valid_in && flag) begin
                data_out <= {data_lock, data_in};
                valid_out <= 1'b1;
                flag <= 1'b0;
            end
            else begin
                valid_out <= 1'b0;
            end
        end
    end
endmodule

module pe
(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output [31:0] c
);
reg [31:0] c_reg;
always @(posedge clk or posedge rst) begin
    if (rst) begin
        c_reg <= 32'd0;
    end else begin
        c_reg <= c_reg + (a * b);
    end
end
assign c = c_reg;
endmodule

module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [1:0] state;
reg [1:0] next_state;
reg [7:0] cnt;
reg [7:0] next_cnt;
reg p_red, p_yellow, p_green;
reg next_red, next_yellow, next_green;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        state <= idle;
        cnt <= 8'd10;
        {p_red, p_yellow, p_green} <= 3'b0;
    end
    else begin
        state <= next_state;
        cnt <= next_cnt;
        {p_red, p_yellow, p_green} <= {next_red, next_yellow, next_green};
    end
end
always @(*) begin
    case(state)
        idle: begin
            next_state = s1_red;
            next_cnt = cnt;
            {next_red, next_yellow, next_green} = 3'b0;
        end
        s1_red: begin
            next_state = (cnt == 8'd3) ? s3_green : s1_red;
            next_cnt = (cnt == 8'd3) ? 8'd60 : cnt - 8'd1;
            {next_red, next_yellow, next_green} = (cnt == 8'd3) ? 3'b0 : {p_red, p_yellow, p_green};
        end
        s2_yellow: begin
            next_state = (cnt == 8'd3) ? s1_red : s2_yellow;
            next_cnt = (cnt == 8'd3) ? 8'd10 : cnt - 8'd1;
            {next_red, next_yellow, next_green} = (cnt == 8'd3) ? 3'b0 : {p_red, p_yellow, p_green};
        end
        s3_green: begin
            next_state = (cnt == 8'd3) ? s2_yellow : s3_green;
            next_cnt = (cnt == 8'd3) ? 8'd5 : cnt - 8'd1;
            {next_red, next_yellow, next_green} = (cnt == 8'd3) ? 3'b0 : {p_red, p_yellow, p_green};
        end
        default: begin
            next_state = idle;
            next_cnt = cnt;
            {next_red, next_yellow, next_green} = 3'b0;
        end
    endcase
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        next_cnt = 8'd10;
    end
    else begin
        if(pass_request && s3_green) begin
            next_cnt = 8'd10;
        end
        else if(!s3_green && p_green) begin
            next_cnt = 8'd60;
        end
        else if(!s2_yellow && p_yellow) begin
            next_cnt = 8'd5;
        end
        else if(!s1_red && p_red) begin
            next_cnt = 8'd10;
        end
        else begin
            next_cnt = cnt - 8'd1;
        end
    end
end
assign clock = cnt;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        {red, yellow, green} <= 3'b0;
    end
    else begin
        {red, yellow, green} <= {p_red, p_yellow, p_green};
    end
end
endmodule

module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

    reg [3:0] i;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) i <= 4'd0;
        else if (start && i < 4'd17) i <= i + 1;
        else if (!start) i <= 4'd0;
    end
    reg done_r;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) done_r <= 1'b0;
        else if (i == 4'd16) done_r <= 1'b1;
        else if (i == 4'd17) done_r <= 1'b0;
    end
    assign done = done_r;
    reg [31:0] yout_r;
    reg [15:0] areg;
    reg [15:0] breg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            areg   <= 16'b0;
            breg   <= 16'b0;
            yout_r <= 32'b0;
        end else if (start) begin
            if (i == 4'd0) begin
                areg <= ain;
                breg <= bin;
            end else if (i > 4'd0 && i < 4'd17) begin
                if (areg[i-1'b1]) yout_r <= (yout_r + (breg << (i-1))) ;
            end
        end
    end
    assign yout = yout_r;
endmodule

module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output reg valid_out,
    output reg dout
);

input clk;
input rst_n;
input [3:0] d;
output reg valid_out;
output reg dout;

reg [3:0] data;
reg [1:0] cnt;
reg valid;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        valid_out <= 1'b0;
        dout <= 1'b0;
        data <= 4'b0;
        cnt <= 2'b0;
        valid <= 1'b0;
    end else begin
        if (cnt == 2'd3) begin
            data <= d;
            cnt <= 2'd0;
            valid_out <= 1'b1;
            dout <= data[3];
            valid <= 1'b1;
        end else begin
            cnt <= cnt + 1;
            valid_out <= 1'b0;
            dout <= data[3];
            valid <= 1'b0;
            data <= {data[2:0], data[3]};
        end
    end
end
endmodule

module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);

    reg [15:0] temp_dividend;
    reg [7:0] temp_divisor;
    reg [15:0] temp_quotient;
    reg [15:0] temp_remainder;

    always @(*) begin
        temp_dividend = dividend;
        temp_divisor = divisor;
        temp_quotient = 0;
        temp_remainder = 0;

        if (temp_divisor == 0) begin
            temp_quotient = 16'hFFFF; 
            temp_remainder = temp_dividend; 
        end
        else begin
            while (temp_dividend >= temp_divisor) begin
                temp_dividend = temp_dividend - temp_divisor;
                temp_quotient = {temp_quotient[14:0], 1'b1};
            end
            temp_remainder = temp_dividend;
        end
    end

    assign quotient = temp_quotient;
    assign remainder = temp_remainder;

endmodule

module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [7:0] multiplicand;
    reg [7:0] multiplier;
    reg [15:0] partial_product;
    reg [3:0] count;
    always @(*) begin

        if (count == 0) begin
            product = 16'd0;
            multiplicand = A;
            multiplier = B;
            partial_product = 16'd0;
            count = 4'd0;
        end

        else begin
            if (multiplier[0] == 1'b1) begin
                partial_product = partial_product + {8'd0, multiplicand};
            end
            multiplicand = multiplicand << 1;
            multiplier = multiplier >> 1;
        end
    end
    always @(posedge clk) begin
        if (count < 8) begin
            count <= count + 1;
        end
        else begin
            count <= count;
        end
    end
endmodule

module fsm
