module freq_div
(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);
reg [3:0] cnt_10;
reg [6:0] cnt_100;
always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        CLK_50 <= 1'b0;
        CLK_10 <= 1'b0;
        CLK_1 <= 1'b0;
        cnt_10 <= 4'b0;
        cnt_100 <= 7'b0;
    end
    else begin

        CLK_50 <= ~CLK_50;

        if (cnt_10 == 4'd4) begin
            CLK_10 <= ~CLK_10;
            cnt_10 <= 4'b0;
        end
        else begin
            cnt_10 <= cnt_10 + 4'b1;
        end

        if (cnt_100 == 7'd49) begin
            CLK_1 <= ~CLK_1;
            cnt_100 <= 7'b0;
        end
        else begin
            cnt_100 <= cnt_100 + 7'b1;
        end
    end
end
endmodule

module alu
(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;
    wire signed [31:0] a_signed = a;
    wire signed [31:0] b_signed = b;
    reg [31:0] res;
    reg [32:0] temp;
    assign r = res;
    assign zero = res == 0;
    assign carry = temp[32];
    assign negative = res[31];
    assign overflow = temp[31] ^ temp[30];
    assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 1'bz;
    always @(*) begin
        case (aluc)
            ADD: {temp[32], res} = a_signed + b_signed;
            ADDU: {temp[32], res} = a + b;
            SUB: {temp[32], res} = a_signed - b_signed;
            SUBU: {temp[32], res} = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: res = a_signed < b_signed ? 1 : 0;
            SLTU: res = a < b ? 1 : 0;
            SLL: res = b << a[4:0];
            SRL: res = b >> a[4:0];
            SRA: res = b_signed >>> a[4:0];
            SLLV: res = b << a[4:0];
            SRLV: res = b >> a[4:0];
            SRAV: res = b_signed >>> a[4:0];
            LUI: res = {b[15:0], 16'b0};
            default: res = 0;
        endcase
    end
endmodule

module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

reg a_prev;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a_prev <= 1'b0;
        rise <= 1'b0;
        down <= 1'b0;
    end else begin
        a_prev <= a;
        rise <= 1'b0;
        down <= 1'b0;

        if (a_prev == 1'b0 && a == 1'b1) begin
            rise <= 1'b1;
        end else if (a_prev == 1'b1 && a == 1'b0) begin
            down <= 1'b1;
        end
    end
end

endmodule

module adder_16bit
(
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [15:0] carry;
    wire [15:0] sum;
    assign {carry[0], sum[0]} = a[0] + b[0] + Cin;
    genvar i;
    generate
        for (i = 1; i < 16; i = i + 1) begin : adder_gen
            assign {carry[i], sum[i]} = a[i] + b[i] + carry[i - 1];
        end
    endgenerate
    assign y = sum;
    assign Co = carry[15];
endmodule

module multi_pipe_4bit #(
    parameter size = 4
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    output reg [2*size-1:0] mul_out
);

    wire [size-1:0] extend_a;
    wire [size-1:0] extend_b;
    assign extend_a = mul_a;
    assign extend_b = mul_b;

    wire [2*size-1:0] partial_products [size-1:0];
    genvar i;
    generate
        for (i = 0; i < size; i = i + 1) begin
            assign partial_products[i] = (extend_b[i]) ? (extend_a << i) : 'd0;
        end
    endgenerate

    reg [2*size-1:0] pp_reg [size-1:0];
    integer j;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (j = 0; j < size; j = j + 1) begin
                pp_reg[j] <= 'd0;
            end
        end else begin
            pp_reg[0] <= partial_products[0];
            for (j = 1; j < size; j = j + 1) begin
                pp_reg[j] <= pp_reg[j-1] + partial_products[j];
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 'd0;
        end else begin
            mul_out <= pp_reg[size-1];
        end
    end

endmodule

module calendar
(
    input CLK,
    input RST,
    output [5:0] Hours,
    output [5:0] Mins,
    output [5:0] Secs
);

    always @(posedge CLK or posedge RST) begin
        if (RST) Secs <= 6'b000000;
        else if (Secs == 6'b111011) Secs <= 6'b000000;
        else Secs <= Secs + 1;
    end
    always @(posedge CLK or posedge RST) begin
        if (RST) Mins <= 6'b000000;
        else if (&Mins == 6'b111011 && Secs == 6'b111011) Mins <= 6'b000000;
        else if (Secs == 6'b111011) Mins <= Mins + 1;
        else Mins <= Mins;
    end
    always @(posedge CLK or posedge RST) begin
        if (RST) Hours <= 6'b000000;
        else if (&Hours == 6'b101101 && Mins == 6'b111011 && Secs == 6'b111011) Hours <= 6'b000000;
        else if (&Mins == 6'b111011 && Secs == 6'b111011) Hours <= Hours + 1;
        else Hours <= Hours;
    end
endmodule

module counter_12
(
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            out <= 4'd0;
        else if (valid_count) begin
            if (out == 4'd11) out <= 4'd0;
            else              out <= out + 1;
        end
    end
endmodule

module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [31:0] P, G;
