module adder_8bit
(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);

    wire [6:0] carry;
    wire [7:0] s;
    assign s[0] = a[0] ^ b[0] ^ cin;
    assign carry[0] = (a[0] & b[0]) | (b[0] & cin) | (cin & a[0]);
    assign s[1] = a[1] ^ b[1] ^ carry[0];
    assign carry[1] = (a[1] & b[1]) | (b[1] & carry[0]) | (carry[0] & a[1]);
    assign s[2] = a[2] ^ b[2] ^ carry[1];
    assign carry[2] = (a[2] & b[2]) | (b[2] & carry[1]) | (carry[1] & a[2]);
    assign s[3] = a[3] ^ b[3] ^ carry[2];
    assign carry[3] = (a[3] & b[3]) | (b[3] & carry[2]) | (carry[2] & a[3]);
    assign s[4] = a[4] ^ b[4] ^ carry[3];
    assign carry[4] = (a[4] & b[4]) | (b[4] & carry[3]) | (carry[3] & a[4]);
    assign s[5] = a[5] ^ b[5] ^ carry[4];
    assign carry[5] = (a[5] & b[5]) | (b[5] & carry[4]) | (carry[4] & a[5]);
    assign s[6] = a[6] ^ b[6] ^ carry[5];
    assign carry[6] = (a[6] & b[6]) | (b[6] & carry[5]) | (carry[5] & a[6]);
    assign s[7] = a[7] ^ b[7] ^ carry[6];
    assign cout = (a[7] & b[7]) | (b[7] & carry[6]) | (carry[6] & a[7]);
    assign sum = s;
endmodule

module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);

reg [1:0] count;
reg [9:0] sum;
reg [1:0] state;
parameter IDLE = 2'b00;
parameter INPUT = 2'b01;
parameter ACCUMULATE = 2'b10;
parameter OUTPUT = 2'b11;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        count <= 2'b00;
        sum <= 10'b0;
        valid_out <= 1'b0;
        data_out <= 10'b0;
    end else begin
        case (state)
            IDLE: begin
                if (valid_in) begin
                    state <= INPUT;
                    count <= 2'b01;
                    sum <= {2'b00, data_in};
                end else begin
                    state <= IDLE;
                    count <= 2'b00;
                    sum <= 10'b0;
                end
            end
            INPUT: begin
                if (count == 2'b11) begin
                    state <= ACCUMULATE;
                    count <= 2'b00;
                    sum <= sum + {2'b00, data_in};
                end else begin
                    state <= INPUT;
                    count <= count + 1;
                    sum <= sum + {2'b00, data_in};
                end
            end
            ACCUMULATE: begin
                state <= OUTPUT;
            end
            OUTPUT: begin
                state <= IDLE;
                valid_out <= 1'b0;
                data_out <= sum;
            end
            default: begin
                state <= IDLE;
                count <= 2'b00;
                sum <= 10'b0;
            end
        endcase
    end
end

endmodule

module right_shifter
(
    input clk,
    input d,
    output reg q
);
initial begin
    q = 8'b00000000;
end
always @(posedge clk) begin
    q <= (q >> 1);
    q[7] <= d;
end
endmodule

module synchronizer
(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);

reg [3:0] data_reg;

reg en_data_reg;

reg en_clap_one;
reg en_clap_two;

always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        data_reg <= 4'b0;
    end else begin
        data_reg <= data_in;
    end
end

always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        en_data_reg <= 1'b0;
    end else begin
        en_data_reg <= data_en;
    end
end

always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        en_clap_one <= 1'b0;
    end else begin
        en_clap_one <= en_data_reg;
    end
end

always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        en_clap_two <= 1'b0;
    end else begin
        en_clap_two <= en_clap_one;
    end
end

always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        dataout <= 4'b0;
    end else begin
        if (en_clap_two) begin
            dataout <= data_reg;
        end else begin
            dataout <= dataout;
        end
    end
end
endmodule
